<span class="line"><span style="color:#CBA6F7;">        let</span><span style="color:#CDD6F4;"> end </span><span style="color:#94E2D5;">=</span><span style="color:#9399B2;"> (</span><span style="color:#CDD6F4;">idx </span><span style="color:#94E2D5;">+</span><span style="color:#FAB387;"> 3</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">min</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">lines</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">len</span><span style="color:#9399B2;">());</span></span>
